{
  "experiment_plan": {
    "what_to_compare": "米国の8年生・10年生・12年生について、1991〜2016年の年次横断調査を用い、(1) 2012年前後のスクリーンタイム水準と幸福感指標の時系列変化、(2) スクリーン活動別（ソーシャルメディア、インターネット、テレビ、ゲーム）の変化幅、(3) 高スクリーンタイム群と低スクリーンタイム群の同年比較を行う。比較単位は年×学年×活動別で、必要に応じて個人レベルの群比較も行う。",
    "what_to_measure": "主要アウトカムは幸福感、自尊心、生活満足度。主要説明変数は総スクリーンタイムおよび活動別スクリーンタイム。補助的に、年次変化量、群間差、幸福感の低さとスクリーンタイムの先後関係を確認する。各年・学年・活動別に平均値または割合を算出し、2012年以降の変化勾配を比較する。",
    "procedure": "1) 1991〜2016年の各年について、8年生・10年生・12年生別にスクリーンタイムと幸福感指標を集計する。2) 2012年前後で変化点を置き、前後の平均水準と傾きを比較する。3) 活動別に、ソーシャルメディア、インターネット、テレビ、ゲームの各利用増加と幸福感指標の変化を同一尺度で比較する。4) 高スクリーンタイム群と低スクリーンタイム群の幸福感差を年次ごとに確認する。5) 逆因果チェックとして、幸福感の低さが先行してスクリーンタイム増加に結びつくパターンがあるかを確認する。6) 主要な判定は事前に定義した accept_if / reject_if / hold_if に従い、単一の指標ではなく複数の整合的証拠で判断する。",
    "decision_rule": "各仮説は独立に、事前定義した判定規則に従って評価する。exclusive な仮説ペアでは、一方の reject が他方の accept を強く支持しうるが、nested または independent の関係では他仮説の判定を自動的には決めない。主要判定は、(a) 時系列の方向性、(b) 群間差の一貫性、(c) 活動別の異質性、(d) 逆因果の有無、の4系統の証拠が一致するかで行う。証拠が混在する場合は hold とする。",
    "checks": [
      "2012年前後でスクリーンタイムが実際に増加しているかを確認する。",
      "幸福感、自尊心、生活満足度の各指標が同方向に変化しているかを確認する。",
      "活動別の変化が同じ方向か、特定活動に偏っているかを確認する。",
      "高スクリーンタイム群と低スクリーンタイム群の年次差が一貫しているかを確認する。",
      "幸福感の低さが先行してスクリーンタイム増加を予測する逆因果パターンがないかを確認する。",
      "学年別に結果が大きく異ならないかを確認する。"
    ],
    "check_targets": [
      {
        "check": "2012年前後のスクリーンタイム増加",
        "targets": [
          "H1",
          "H2",
          "H3",
          "H4"
        ],
        "if_positive": "2012年以降にスクリーンタイムが明確に増加していれば、H1の前提整合性は高まり、H2/H3/H4の判定では説明変数の変動が十分あるとみなす。",
        "if_negative": "スクリーンタイムが増加していなければ、H1は支持されにくく、H2/H3/H4もスクリーンタイム起点の説明としては hold へ寄せる。"
      },
      {
        "check": "幸福感指標の同方向低下",
        "targets": [
          "H1",
          "H2",
          "H3"
        ],
        "if_positive": "幸福感、自尊心、生活満足度が同方向に低下していれば、H1またはH2/H3のいずれかの説明が必要になる。",
        "if_negative": "幸福感指標が低下していなければ、H1は reject 寄り、H2/H3は hold または reject 寄りになる。"
      },
      {
        "check": "活動別の異質性",
        "targets": [
          "H4",
          "H1"
        ],
        "if_positive": "ソーシャルメディアやゲームのみが強く関連し、テレビが弱いならH4を支持し、H1は一般化の強さを下げて hold へ寄せる。",
        "if_negative": "全活動が同程度ならH4は reject 寄りで、H1の一般的主張は相対的に強まる。"
      },
      {
        "check": "逆因果パターン",
        "targets": [
          "H3",
          "H1"
        ],
        "if_positive": "幸福感の低さが先行してスクリーンタイム増加を予測するならH3を支持し、H1は reject 寄りになる。",
        "if_negative": "幸福感の低さが先行しないならH3は reject 寄りで、H1の因果方向と整合的になる。"
      }
    ],
    "hypothesis_rules": [
      {
        "id": "H1",
        "accept_if": "2012年以降にスクリーンタイムが増加し、同時期に幸福感・自尊心・生活満足度が一貫して低下し、かつ高スクリーンタイム群が低スクリーンタイム群より低い幸福感を示し、活動別にも複数媒体で同方向の関連が観察される場合。",
        "reject_if": "2012年以降にスクリーンタイムが増加していても、幸福感・自尊心・生活満足度が低下しない、または低スクリーンタイム群と同等以上である、あるいは時系列対応が一貫せず、逆因果パターンが優勢な場合。",
        "hold_if": "スクリーンタイム増加と幸福感低下の一部は一致するが、活動別に不一致が大きい、学年差が大きい、または逆因果・別要因の可能性を排除できない場合。"
      },
      {
        "id": "H2",
        "accept_if": "スクリーンタイムの年次変化や群間差を考慮しても、2012年以降の幸福感低下がなお説明され、かつスクリーンタイム水準の高低に応じた幸福感の系統的差が弱い、または不安定である場合。",
        "reject_if": "スクリーンタイムの増加を考慮すると幸福感低下が十分に説明されなくなり、さらに高スクリーンタイム群ほど一貫して幸福感が低い場合。",
        "hold_if": "別要因の時系列変化を示唆するが、スクリーンタイムとの独立性が十分に確認できない、またはスクリーンタイム調整後の残差的低下が不明確な場合。"
      },
      {
        "id": "H3",
        "accept_if": "幸福感の低さが先行してスクリーンタイム増加を予測し、スクリーンタイム増加が幸福感低下を先導する証拠が弱く、さらに低幸福感群でスクリーンタイムが高いという方向の関連が一貫する場合。",
        "reject_if": "高スクリーンタイム群がその後に一貫して幸福感低下を示し、低スクリーンタイム群より先行して悪化する、または幸福感の低さを調整してもスクリーンタイム増加が幸福感低下を予測する場合。",
        "hold_if": "逆因果の兆候はあるが、時間順序が不明確、またはスクリーンタイム→幸福感と幸福感→スクリーンタイムの両方向の証拠が混在する場合。"
      },
      {
        "id": "H4",
        "accept_if": "ソーシャルメディアやゲームの増加が幸福感低下と強く関連し、テレビ視聴は弱いか無関係で、活動別の勾配差が一貫して観察される場合。",
        "reject_if": "すべてのスクリーン活動が同程度に幸福感低下と関連する、または特定活動に限定された差が観察されない場合。",
        "hold_if": "活動別の差はあるが、媒体間の順位づけが年や学年で不安定で、特定活動に限定された効果と断定できない場合。"
      }
    ],
    "rule_consistency_audit": [
      {
        "id": "H1",
        "accept_reject_overlap": "none",
        "note": "accept は複数媒体での一貫した時系列一致と群間差を要求し、reject はその不成立または逆因果優勢を要求するため、同じ意味にはならない。"
      },
      {
        "id": "H2",
        "accept_reject_overlap": "none",
        "note": "accept はスクリーンタイム調整後も別要因で説明されること、reject はスクリーンタイム調整で説明が消えることを要求し、対立が明確である。"
      },
      {
        "id": "H3",
        "accept_reject_overlap": "none",
        "note": "accept は幸福感→スクリーンタイムの先行を要求し、reject はスクリーンタイム→幸福感の先行を要求するため、意味は反対である。"
      },
      {
        "id": "H4",
        "accept_reject_overlap": "none",
        "note": "accept は活動別の異質性を要求し、reject は全活動で同程度または差なしを要求するため、同義ではない。"
      }
    ],
    "tie_breaker_rule": "証拠が拮抗する場合は、より強い識別を要する主張を優先せず hold とする。具体的には、単年の一致よりも複数年の一貫性を優先し、総スクリーンタイムの結果と活動別結果が矛盾する場合は、H1は hold、H4は活動別証拠に基づき独立に判定する。"
  },
  "identification_assumptions": [
    {
      "id": "IA1",
      "assumption": "年次横断データの各年サンプルが、同年の米国8年生・10年生・12年生を代表していること。",
      "if_violated": "特定年や特定学年に偏ると、時系列変化が母集団変化ではなくサンプル構成変化を反映し、スクリーンタイムと幸福感の関連が過大または過小に歪む。"
    },
    {
      "id": "IA2",
      "assumption": "スクリーンタイムと幸福感指標が各年で同等の意味と測定尺度を持ち、測定不変性が概ね成り立つこと。",
      "if_violated": "質問文や尺度変更があると、見かけの時系列変化が測定変更に由来し、真の変化より大きくまたは小さく見える。"
    },
    {
      "id": "IA3",
      "assumption": "2012年前後のスクリーンタイム変化が、幸福感に影響しうる主要な観察可能変化として十分に捉えられていること。",
      "if_violated": "主要なスクリーン利用の変化が未観測だと、スクリーンタイムの効果は希釈され、H1の支持が弱く見える。"
    },
    {
      "id": "IA4",
      "assumption": "年次比較において、同時期に変化する別の社会的・経済的要因がスクリーンタイムと強く共変しすぎないこと、または少なくともその影響を別途確認できること。",
      "if_violated": "別要因がスクリーンタイムと同時に動くと、スクリーンタイムの見かけの関連が交絡され、H1を過大評価し、H2を過小評価する。"
    },
    {
      "id": "IA5",
      "assumption": "高スクリーンタイム群と低スクリーンタイム群の比較で、群分けが極端な測定誤差や逆選択を生まないこと。",
      "if_violated": "群分け誤差が大きいと群間差が縮小し、真の関連が見えにくくなる。逆選択が強いと、低幸福感が先に高スクリーンタイム群へ集まり、H3が過大に見える。"
    },
    {
      "id": "IA6",
      "assumption": "活動別スクリーンタイムの分類が互いに十分区別され、ソーシャルメディア、インターネット、テレビ、ゲームの利用が概ね別個に測定されること。",
      "if_violated": "活動の混同があると、特定活動の効果が他活動に漏れ、H4の異質性が不明瞭になり、全活動が同程度に見える方向へ歪む。"
    },
    {
      "id": "IA7",
      "assumption": "横断データからの時系列解釈では、年次平均の変化が個人内変化の代理として完全ではないことを認識しつつ、少なくとも集団レベルの同期変化を比較するという限定的な識別が妥当であること。",
      "if_violated": "個人内因果を年次平均から過度に推論すると、生態学的誤謬が生じ、スクリーンタイムが原因であるという結論を過大に解釈する。"
    }
  ]
}
